import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, FormGroup, Validators } from '@angular/forms';

interface PatientRecord {
  id: string;
  firstName: string;
  lastName: string;
  nic: string;
  email: string;
  mobile: string;
  dob: string;
  gender: string;
  address: string;
}

@Component({
  selector: 'app-patient',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './patient.component.html',
  styleUrls: ['./patient.component.scss']
})
export class PatientComponent implements OnInit {
  patientForm!: FormGroup;

  patientList: PatientRecord[] = [
    { id: '1', firstName: 'Sam', lastName: 'Rupash', nic: '123456789V', email: 'sam@gmail.com', mobile: '0714942914', dob: '1995-10-12', gender: 'Male', address: 'Galle' }
  ];

  constructor(private fb: FormBuilder) {}

  ngOnInit(): void {
    this.initForm();
  }

  initForm(): void {
    this.patientForm = this.fb.group({
      firstName: ['', Validators.required],
      lastName: ['', Validators.required],
      email: ['', [Validators.required, Validators.email]],
      mobile: ['', Validators.required],
      nic: ['', Validators.required],
      dob: ['', Validators.required],
      address: ['', Validators.required],
      gender: ['Male', Validators.required],
      password: ['', Validators.required],
      confirmPassword: ['', Validators.required]
    });
  }

  onAdd(): void {
    if (this.patientForm.valid) {
      const newPatient: PatientRecord = {
        id: (this.patientList.length + 1).toString(),
        ...this.patientForm.value
      };
      this.patientList.push(newPatient);
      this.patientForm.reset({ gender: 'Male' });
    } else {
      this.patientForm.markAllAsTouched();
    }
  }

  onSearch(id: string): void {
    const pt = this.patientList.find(p => p.id === id);
    if (pt) this.patientForm.patchValue(pt);
  }
}
